26	function findLastUpdateMarker(response: string): { index: number; end: number } | null {
27	  let lastMarker: { index: number; end: number } | null = null;
28	  for (const match of response.matchAll(UPDATE_MARKER_PATTERN)) {
29	    const leadingNewline = match[1] ?? "";
30	    lastMarker = {
31	      index: match.index + leadingNewline.length,
32	      end: match.index + match[0].length
33	    };
34	  }
35	
36	  if (lastMarker) {
37	    return lastMarker;
38	  }
39	
40	  const legacyIndex = response.lastIndexOf(UPDATE_MARKER);
41	  return legacyIndex >= 0 ? { index: legacyIndex, end: legacyIndex + UPDATE_MARKER.length } : null;
42	}
