51	function normalizeUpdateJsonText(rawText: string): string {
52	  let trimmed = rawText.trim();
53	  if (!trimmed.startsWith("```")) {
54	    return extractFirstJsonObject(trimmed);
55	  }
56	
57	  const firstLineEnd = trimmed.indexOf("\n");
58	  if (firstLineEnd < 0) {
59	    return trimmed;
60	  }
61	
62	  const withoutFenceStart = trimmed.slice(firstLineEnd + 1).trim();
63	  const fenceEnd = withoutFenceStart.lastIndexOf("```");
64	  if (fenceEnd < 0) {
65	    trimmed = withoutFenceStart;
66	  } else {
67	    trimmed = withoutFenceStart.slice(0, fenceEnd).trim();
68	  }
69	
70	  return extractFirstJsonObject(trimmed);
71	}
