73	function extractFirstJsonObject(text: string): string {
74	  const start = text.indexOf("{");
75	  if (start < 0) {
76	    return text.trim();
77	  }
78	
79	  let depth = 0;
80	  let inString = false;
81	  let escaped = false;
82	
83	  for (let index = start; index < text.length; index += 1) {
84	    const char = text[index];
85	
86	    if (escaped) {
87	      escaped = false;
88	      continue;
89	    }
90	
91	    if (char === "\\") {
92	      escaped = inString;
93	      continue;
94	    }
95	
96	    if (char === '"') {
97	      inString = !inString;
98	      continue;
99	    }
100	
101	    if (inString) {
102	      continue;
103	    }
104	
105	    if (char === "{") {
106	      depth += 1;
107	    } else if (char === "}") {
108	      depth -= 1;
109	      if (depth === 0) {
110	        return text.slice(start, index + 1).trim();
111	      }
112	    }
113	  }
114	
115	  return text.slice(start).trim();
116	}
