121	    decisions: sanitizeStringArray(update.decisions, 10, 300),
122	    open_questions: sanitizeStringArray(update.open_questions, 5, 300),
123	    files_discussed: sanitizeStringArray(update.files_discussed, 20, 200),
124	    tags: sanitizeStringArray(update.tags, 8, 50).map((tag) => tag.toLowerCase()),
125	    aliases: sanitizeStringArray(update.aliases, 12, 80).map((alias) => alias.toLowerCase())
126	  };
127	}
