129	function sanitizeStringArray(value: unknown, maxItems: number, maxLength: number): string[] {
130	  const items = Array.isArray(value) ? value : [];
131	  const seen = new Set<string>();
132	  const result: string[] = [];
133	
134	  for (const item of items) {
135	    const normalized = String(item).trim();
136	    if (!normalized || seen.has(normalized)) {
137	      continue;
138	    }
139	    seen.add(normalized);
140	    result.push(normalized.slice(0, maxLength));
141	    if (result.length >= maxItems) {
142	      break;
143	    }
144	  }
